import type { CompleteVerbEntry } from './completeVerbEntry';
import { COMPLETE_VERB_MAPPINGS } from './completeVerbMappings';

export type ConjugationGroup = '-ar' | '-er' | '-ir';

export interface VerbEntry {
  infinitive: string;
  voseo: string;
  tuteo: string;
  ustedeo: string;
  voseoImperative?: string;
  tuteoImperative?: string;
  ustedeoImperative?: string;
  isIrregular: boolean;
  isDiphthongating: boolean;
  conjugationGroup: ConjugationGroup;
}

function toVerbEntry(e: CompleteVerbEntry): VerbEntry {
  return {
    infinitive: e.infinitive,
    voseo: e.presenteInd.voseo,
    tuteo: e.presenteInd.tuteo,
    ustedeo: e.presenteInd.ustedeo,
    voseoImperative: e.imperativoPos.voseo,
    tuteoImperative: e.imperativoPos.tuteo,
    ustedeoImperative: e.imperativoPos.ustedeo,
    isIrregular: e.isIrregular,
    isDiphthongating: e.isDiphthongating,
    conjugationGroup: e.conjugationGroup,
  };
}

